import { BaseCommand } from "../../core/interfaces/BaseCommand.js";
import { ServiceRegistry } from "../../core/registry/ServiceRegistry.js";
import { ILogger } from "../../core/logging/ILogger.js";
import { LoggerFactory } from "../../core/logging/LoggerFactory.js";
import { CLIError } from "../../types/CLITypes.js";
import { spawn } from "child_process";
import { promises as fs } from "fs";
import path from "path";
import chalk from "chalk";
import ora from "ora";

/**
 * InitCommand - MCF CLI Repository Initialization
 * Clones the MCF GitHub repository to initialize a new MCF project
 */
export class InitCommand extends BaseCommand {
  constructor(serviceRegistry) {
    super();
    this.serviceRegistry = serviceRegistry;
    this.logger = LoggerFactory.getLogger("InitCommand");
    this.fileSystemService = null;
  }

  static get metadata() {
    return {
      name: "InitCommand",
      description: "Initialize a new MCF project by cloning the repository",
      category: "init",
      version: "1.0.0",
      dependencies: {
        services: ["IFileSystemService"],
        commands: [],
        external: ["git"]
      }
    };
  }

  async initialize() {
    try {
      this.fileSystemService = this.serviceRegistry.getService("IFileSystemService");
      this.logger.debug("InitCommand initialized with services");
    } catch (error) {
      this.logger.error("Failed to initialize InitCommand", error);
      throw new CLIError(
        "Failed to initialize file system services",
        "INIT_COMMAND_INIT_FAILED"
      );
    }
  }

  async execute(args = []) {
    await this.initialize();

    // Parse arguments
    const parsedArgs = this.parseArguments(args);

    if (parsedArgs.showHelp) {
      return this.showHelp();
    }

    const targetDirectory = parsedArgs.directory || "MCF";
    const repositoryUrl = "https://github.com/pc-style/MCF.git";

    console.log(chalk.blue.bold("🚀 MCF Project Initialization"));
    console.log();

    try {
      // Check if git is available
      await this.checkGitAvailability();

      // Check if target directory already exists
      await this.checkTargetDirectory(targetDirectory, parsedArgs.force);

      // Clone the repository
      await this.cloneRepository(repositoryUrl, targetDirectory, parsedArgs);

      // Display success message and next steps
      this.showSuccessMessage(targetDirectory);

    } catch (error) {
      this.logger.error("Init command failed", error);
      console.error(chalk.red(`❌ Failed to initialize MCF project: ${error.message}`));
      throw error;
    }
  }

  /**
   * Parse command line arguments
   */
  parseArguments(args) {
    const result = {
      directory: null,
      branch: null,
      force: false,
      shallow: true,
      showHelp: false
    };

    for (let i = 0; i < args.length; i++) {
      const arg = args[i];

      switch (arg) {
        case "-h":
        case "--help":
          result.showHelp = true;
          break;

        case "-d":
        case "--directory":
          if (i + 1 < args.length) {
            result.directory = args[++i];
          } else {
            throw new CLIError("--directory requires a directory name", "MISSING_DIRECTORY_VALUE");
          }
          break;

        case "-b":
        case "--branch":
          if (i + 1 < args.length) {
            result.branch = args[++i];
          } else {
            throw new CLIError("--branch requires a branch name", "MISSING_BRANCH_VALUE");
          }
          break;

        case "-f":
        case "--force":
          result.force = true;
          break;

        case "--no-shallow":
          result.shallow = false;
          break;

        default:
          // Treat as positional argument (directory name)
          if (!arg.startsWith("-") && !result.directory) {
            result.directory = arg;
          } else if (arg.startsWith("-")) {
            console.log(chalk.yellow(`⚠️  Unknown option: ${arg}`));
          } else {
            console.log(chalk.yellow(`⚠️  Ignoring unexpected argument: ${arg}`));
          }
      }
    }

    return result;
  }

  /**
   * Check if git is available on the system
   */
  async checkGitAvailability() {
    return new Promise((resolve, reject) => {
      const git = spawn("git", ["--version"], { stdio: "pipe" });

      git.on("close", (code) => {
        if (code === 0) {
          this.logger.debug("Git is available");
          resolve();
        } else {
          reject(new CLIError(
            "Git is not available. Please install git to use the init command.",
            "GIT_NOT_AVAILABLE"
          ));
        }
      });

      git.on("error", (error) => {
        reject(new CLIError(
          `Git is not available: ${error.message}. Please install git to use the init command.`,
          "GIT_NOT_AVAILABLE"
        ));
      });
    });
  }

  /**
   * Check if target directory exists and handle accordingly
   */
  async checkTargetDirectory(targetDirectory, force) {
    const absolutePath = path.resolve(process.cwd(), targetDirectory);

    try {
      const stats = await fs.stat(absolutePath);

      if (stats.isDirectory()) {
        // Check if directory is empty
        const files = await fs.readdir(absolutePath);
        if (files.length > 0) {
          if (!force) {
            throw new CLIError(
              `Directory '${targetDirectory}' already exists and is not empty. Use --force to overwrite.`,
              "DIRECTORY_NOT_EMPTY"
            );
          } else {
            console.log(chalk.yellow(`⚠️  Directory '${targetDirectory}' exists. Overwriting due to --force flag.`));
          }
        }
      } else {
        throw new CLIError(
          `'${targetDirectory}' exists but is not a directory.`,
          "PATH_NOT_DIRECTORY"
        );
      }
    } catch (error) {
      if (error.code === "ENOENT") {
        // Directory doesn't exist, which is fine
        this.logger.debug(`Target directory '${targetDirectory}' does not exist, will create it`);
      } else if (error instanceof CLIError) {
        throw error;
      } else {
        throw new CLIError(
          `Failed to check target directory: ${error.message}`,
          "DIRECTORY_CHECK_FAILED"
        );
      }
    }
  }

  /**
   * Clone the MCF repository
   */
  async cloneRepository(repositoryUrl, targetDirectory, options) {
    const spinner = ora("Cloning MCF repository...").start();

    return new Promise((resolve, reject) => {
      // Build git clone arguments
      const gitArgs = ["clone"];

      if (options.shallow) {
        gitArgs.push("--depth", "1");
      }

      if (options.branch) {
        gitArgs.push("--branch", options.branch);
      }

      gitArgs.push(repositoryUrl, targetDirectory);

      // Execute git clone
      const git = spawn("git", gitArgs, {
        stdio: ["inherit", "pipe", "pipe"],
        cwd: process.cwd()
      });

      let stdout = "";
      let stderr = "";

      git.stdout.on("data", (data) => {
        stdout += data.toString();
        // Update spinner with progress if available
        const output = data.toString().trim();
        if (output) {
          spinner.text = `Cloning MCF repository... ${output.split('\n').pop()}`;
        }
      });

      git.stderr.on("data", (data) => {
        stderr += data.toString();
        // Git often sends progress to stderr
        const output = data.toString().trim();
        if (output && !output.toLowerCase().includes("error")) {
          spinner.text = `Cloning MCF repository... ${output.split('\n').pop()}`;
        }
      });

      git.on("close", (code) => {
        if (code === 0) {
          spinner.succeed("MCF repository cloned successfully!");
          this.logger.info(`Repository cloned to ${targetDirectory}`);
          resolve();
        } else {
          spinner.fail("Failed to clone MCF repository");
          const errorMessage = stderr || stdout || "Unknown git error";
          this.logger.error("Git clone failed", { code, stderr, stdout });
          reject(new CLIError(
            `Git clone failed: ${errorMessage}`,
            "GIT_CLONE_FAILED"
          ));
        }
      });

      git.on("error", (error) => {
        spinner.fail("Failed to clone MCF repository");
        this.logger.error("Git clone process error", error);
        reject(new CLIError(
          `Git clone failed: ${error.message}`,
          "GIT_CLONE_PROCESS_ERROR"
        ));
      });
    });
  }

  /**
   * Show success message and next steps
   */
  showSuccessMessage(targetDirectory) {
    console.log();
    console.log(chalk.green.bold("✅ MCF project initialized successfully!"));
    console.log();
    console.log(chalk.blue("Next steps:"));
    console.log(`  1. ${chalk.yellow(`cd ${targetDirectory}`)}`);
    console.log(`  2. ${chalk.yellow("mcf install")} - Install MCF framework`);
    console.log(`  3. ${chalk.yellow("mcf setup")} - Configure MCF for your environment`);
    console.log(`  4. ${chalk.yellow("mcf run")} - Start using MCF with Claude Code`);
    console.log();
    console.log(chalk.blue("Documentation:"));
    console.log(`  • README: ${chalk.cyan(path.join(targetDirectory, "README.md"))}`);
    console.log(`  • Documentation: ${chalk.cyan(path.join(targetDirectory, "docs/"))}`);
    console.log();
    console.log(chalk.gray("Happy coding with MCF! 🚀"));
  }

  showHelp() {
    console.log(chalk.blue("MCF Init Command Help"));
    console.log(chalk.gray("─".repeat(50)));
    console.log();
    console.log("Initialize a new MCF project by cloning the repository");
    console.log();
    console.log(chalk.blue("Usage:"));
    console.log("  mcf init [directory] [options]");
    console.log();
    console.log(chalk.blue("Options:"));
    console.log();
    console.log("  -h, --help                Show this help message");
    console.log("  -d, --directory <name>    Target directory name (default: MCF)");
    console.log("  -b, --branch <name>       Clone specific branch (default: main)");
    console.log("  -f, --force               Overwrite existing directory");
    console.log("  --no-shallow              Clone full repository history");
    console.log();
    console.log(chalk.blue("Examples:"));
    console.log();
    console.log("  mcf init                    # Clone into 'MCF' directory");
    console.log("  mcf init my-project         # Clone into 'my-project' directory");
    console.log("  mcf init --branch develop   # Clone 'develop' branch");
    console.log("  mcf init --force            # Overwrite existing directory");
    console.log("  mcf init --no-shallow       # Clone with full history");
    console.log();
    console.log(chalk.blue("What this command does:"));
    console.log();
    console.log("  1. Checks if git is available on your system");
    console.log("  2. Validates target directory (creates if needed)");
    console.log("  3. Clones https://github.com/pc-style/MCF.git");
    console.log("  4. Provides next steps for installation and setup");
    console.log();
    return { success: true };
  }

  getMetadata() {
    return InitCommand.metadata;
  }
}

