    54→
    55→  if (args.includes('--version') || args.includes('-V')) {
    56→    result.showVersion = true;
    57→    return result;
    58→  }
    59→
    60→  // Parse command and options
    61→  result.command = args[0];
    62→
    63→  // Simple option parsing
    64→  for (let i = 1; i < args.length; i++) {
    65→    const arg = args[i];
    66→    if (arg.startsWith('--')) {
    67→      const key = arg.substring(2);
    68→      if (i + 1 < args.length && !args[i + 1].startsWith('--')) {
    69→        result.options[key] = args[i + 1];
    70→        i++; // skip next arg
    71→      } else {
    72→        result.options[key] = true;
    73→      }
    74→    } else if (arg.startsWith('-')) {
    75→      result.options[arg.substring(1)] = true;
    76→    } else {
    77→      result.args.push(arg);
    78→    }
    79→  }
    80→
    81→  if (result.args.length > 0) {
    82→    result.subcommand = result.args[0];
    83→    result.args = result.args.slice(1);
    84→  }
    85→
    86→  return result;
    87→}
