    93→class ConfigurationService {
    94→  constructor() {
    95→    this.configDir = path.join(os.homedir(), '.mcf');
    96→    this.profilesDir = path.join(this.configDir, 'profiles');
    97→  }
    98→
    99→  async ensureConfigDir() {
   100→    await fs.mkdir(this.profilesDir, { recursive: true });
   101→  }
   102→
   103→  async listProfiles() {
   104→    try {
   105→      await this.ensureConfigDir();
   106→      const files = await fs.readdir(this.profilesDir);
   107→      return files
   108→        .filter(file => file.endsWith('.json'))
   109→        .map(file => path.basename(file, '.json'));
   110→    } catch (error) {
   111→      return [];
   112→    }
   113→  }
   114→
   115→  async getProfile(profileName) {
   116→    const profilePath = path.join(this.profilesDir, `${profileName}.json`);
   117→    try {
   118→      const content = await fs.readFile(profilePath, 'utf-8');
   119→      return JSON.parse(content);
   120→    } catch (error) {
   121→      return null;
   122→    }
   123→  }
   124→
   125→  async setProfile(profileName, profileData) {
   126→    await this.ensureConfigDir();
   127→    const profilePath = path.join(this.profilesDir, `${profileName}.json`);
   128→    await fs.writeFile(profilePath, JSON.stringify(profileData, null, 2));
   129→  }
   130→
   131→  async deleteProfile(profileName) {
   132→    const profilePath = path.join(this.profilesDir, `${profileName}.json`);
   133→    try {
   134→      await fs.unlink(profilePath);
   135→      return true;
   136→    } catch (error) {
   137→      return false;
   138→    }
   139→  }
   140→
   141→  createDefaultProfile(name, environment = 'development') {
   142→    return {
   143→      id: this.generateProfileId(name),
   144→      name: name,
   145→      environment: environment,
   146→      version: "1.0.0",
   147→      created: new Date().toISOString(),
   148→      lastUpdated: new Date().toISOString(),
   149→      config: {
   150→        timeout: 60000,
   151→        logLevel: "info",
   152→        maxRetries: 3,
   153→        claude: {
   154→          configDirectory: path.join(this.configDir, 'claude-configs', this.generateProfileId(name))
   155→        }
   156→      },
   157→      permissions: {
   158→        allowedServices: ["claude", "filesystem"],
   159→        blockedServices: []
   160→      }
   161→    };
   162→  }
   163→
   164→  generateProfileId(name) {
   165→    return name.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
   166→  }
   167→}
