   173→/**
   174→ * Simple spinner implementation
   175→ */
   176→function createSpinner(text) {
   177→  const frames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
   178→  let frameIndex = 0;
   179→  let intervalId = null;
   180→  let currentText = text;
   181→
   182→  return {
   183→    start() {
   184→      process.stdout.write('\x1B[?25l'); // Hide cursor
   185→      intervalId = setInterval(() => {
   186→        process.stdout.write(`\r${frames[frameIndex]} ${currentText}`);
   187→        frameIndex = (frameIndex + 1) % frames.length;
   188→      }, 100);
   189→    },
   190→    
   191→    succeed(text) {
   192→      if (intervalId) {
   193→        clearInterval(intervalId);
   194→        intervalId = null;
   195→      }
   196→      process.stdout.write(`\r✅ ${text || currentText}\n`);
   197→      process.stdout.write('\x1B[?25h'); // Show cursor
   198→    },
   199→    
   200→    fail(text) {
   201→      if (intervalId) {
   202→        clearInterval(intervalId);
   203→        intervalId = null;
   204→      }
   205→      process.stdout.write(`\r❌ ${text || currentText}\n`);
   206→      process.stdout.write('\x1B[?25h'); // Show cursor
   207→    },
   208→    
   209→    text(newText) {
   210→      currentText = newText;
   211→    }
   212→  };
   213→}
