   267→/**
   268→ * Clone the MCF repository
   269→ */
   270→async function cloneRepository(repositoryUrl, targetDirectory, options) {
   271→  const spinner = createSpinner("Cloning MCF repository...");
   272→  spinner.start();
   273→
   274→  return new Promise((resolve, reject) => {
   275→    // Build git clone arguments
   276→    const gitArgs = ["clone"];
   277→
   278→    if (options.shallow !== false) {
   279→      gitArgs.push("--depth", "1");
   280→    }
   281→
   282→    if (options.branch) {
   283→      gitArgs.push("--branch", options.branch);
   284→    }
   285→
   286→    gitArgs.push(repositoryUrl, targetDirectory);
   287→
   288→    // Execute git clone
   289→    const git = spawn("git", gitArgs, {
   290→      stdio: ["inherit", "pipe", "pipe"],
   291→      cwd: process.cwd()
   292→    });
   293→
   294→    let stdout = "";
   295→    let stderr = "";
   296→
   297→    git.stdout.on("data", (data) => {
   298→      stdout += data.toString();
   299→      // Update spinner with progress if available
   300→      const output = data.toString().trim();
   301→      if (output) {
   302→        spinner.text(`Cloning MCF repository... ${output.split('\n').pop()}`);
   303→      }
   304→    });
   305→
   306→    git.stderr.on("data", (data) => {
   307→      stderr += data.toString();
   308→      // Git often sends progress to stderr
   309→      const output = data.toString().trim();
   310→      if (output && !output.toLowerCase().includes("error")) {
   311→        spinner.text(`Cloning MCF repository... ${output.split('\n').pop()}`);
   312→      }
   313→    });
   314→
   315→    git.on("close", (code) => {
   316→      if (code === 0) {
   317→        spinner.succeed("MCF repository cloned successfully!");
   318→        resolve();
   319→      } else {
   320→        spinner.fail("Failed to clone MCF repository");
   321→        const errorMessage = stderr || stdout || "Unknown git error";
   322→        reject(new Error(`Git clone failed: ${errorMessage}`));
   323→      }
   324→    });
   325→
   326→    git.on("error", (error) => {
   327→      spinner.fail("Failed to clone MCF repository");
   328→      reject(new Error(`Git clone failed: ${error.message}`));
   329→    });
   330→  });
   331→}
